module TopModule #(
    parameter WIDTH = 8,
    parameter DEPTH = 16
) (
    input wclk,
    input rclk,
    input rstn,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata,
    output reg wfull,
    output reg rempty,
    output reg [WIDTH-1:0] rdata
);
// Your code here
// The RAM module is a dual-port RAM with separate clock, address, data and control signals.
// The RAM module is instantiated from the top module.
// The RAM module must have the following ports: wclk, wenc, waddr, wdata, rclk, renc, raddr, rdata.
// The RAM must have the following functionality: 
//   - wenc is high, wclk is rising edge, waddr is the address to write, wdata is the data to write, write wdata to RAM at waddr.
//   - rclk is rising edge, raddr is the address to read, rdata is the data at raddr.
//   - rclk is rising edge, renc is high, raddr is the address to read, rdata is the data at raddr.
//   - wenc and renc are independent.
    // Declare internal signals
    reg [WIDTH-1:0] RAM_MEM [DEPTH-1:0];
    reg [$clog2(DEPTH)-1:0] waddr;
    reg [$clog2(DEPTH)-1:0] raddr;
    reg [WIDTH-1:0] wdata;
    reg [WIDTH-1:0] rdata_w;
    reg [WIDTH-1:0] rdata_r;
    reg [WIDTH-1:0] rdata_rr;
    reg [WIDTH-1:0] rdata;
    reg [WIDTH-1:0] wptr;
    reg [WIDTH-1:0] rptr;
    reg [WIDTH-1:0] wptr_buff;
    reg [WIDTH-1:0] rptr_buff;
    // Write pointer logic
    always @(posedge wclk or negedge rstn) begin
        if (~rstn) begin
            waddr <= 0;
            wptr <= 0;
        end else begin
            if (winc) begin
                waddr <= waddr + 1;
                wptr <= wptr + 1;
            end
        end
    end
    // Gray code conversion for write pointer
    always @(wptr) begin
        wptr <= wptr ^ (wptr >> 1);
    end
    // Read pointer logic
    always @(posedge rclk or negedge rstn) begin
        if (~rstn) begin
            raddr <= 0;
            rptr <= 0;
        end else begin
            if (rinc) begin
                raddr <= raddr + 1;
                rptr <= rptr + 1;
            end
        end
    end
    // Gray code conversion for read pointer
    always @(rptr) begin
        rptr <= rptr ^ (rptr >> 1);
    end
    // Buffer the read and write pointers
    always @(posedge rclk or negedge rstn) begin
        if (~rstn) begin
            rptr_buff <= 0;
        end else begin
            rptr_buff <= rptr;
        end
    end
    always @(posedge wclk or negedge rstn) begin
        if (~rstn) begin
            wptr_buff <= 0;
        end else begin
            wptr_buff <= wptr;
        end
    end
    // RAM read logic
    always @(posedge rclk) begin
        rdata_w <= RAM_MEM[raddr];
    end
    // RAM write logic
    always @(posedge wclk) begin
        if (winc) begin
            RAM_MEM[waddr] <= wdata;
        end
    end
    // Output logic
    always @(*) begin
        if (rptr_buff == wptr) begin
            rempty = 1;
        end else begin
            rempty = 0;
        end
    end
    always @(*) begin
        if (wptr_buff == rptr) begin
            wfull = 1;
        end else begin
            wfull = 0;
        end
    end
    always @(posedge rclk) begin
        rdata_rr <= rdata_w;
        rdata <= rdata_rr;
    end
endmodule
